+/* =============================================================================
+   EMPTY STATE - Premium placeholder when no content
+   ============================================================================= */
+
+.empty-state {
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+  justify-content: center;
+  padding: var(--space-8) var(--space-4);
+  text-align: center;
+  min-height: 200px;
+}
+
+.empty-state__icon {
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  width: 64px;
+  height: 64px;
+  border-radius: 50%;
+  background: linear-gradient(135deg, var(--color-background-alt), var(--color-background-hover));
+  border: 1px solid var(--color-border-subtle);
+  margin-bottom: var(--space-4);
+  color: var(--color-text-muted);
+  font-size: 28px;
+}
+
+.empty-state__title {
+  font-size: var(--text-lg);
+  font-weight: var(--font-semibold);
+  color: var(--color-text);
+  margin-bottom: var(--space-2);
+}
+
+.empty-state__description {
+  font-size: var(--text-sm);
+  color: var(--color-text-muted);
+  max-width: 320px;
+  line-height: 1.5;
+}
+
+.empty-state__action {
+  margin-top: var(--space-4);
+}
+
+/* Subtle pulse animation for empty state icon */
+@keyframes empty-state-pulse {
+  0%, 100% { opacity: 0.6; transform: scale(1); }
+  50% { opacity: 0.8; transform: scale(1.02); }
+}
+
+.empty-state__icon--animated {
+  animation: empty-state-pulse 3s ease-in-out infinite;
+}
+
+/* =============================================================================
+   TOAST NOTIFICATIONS - Positioned above mobile control deck
+   ============================================================================= */
+
+.toast {
+  position: fixed;
+  left: 50%;
+  transform: translateX(-50%);
+  bottom: calc(var(--space-4) + env(safe-area-inset-bottom));
+  z-index: var(--z-toast, 600);
+  padding: var(--space-3) var(--space-4);
+  background: var(--color-background-elevated);
+  border: 1px solid var(--color-border);
+  border-radius: var(--radius-lg);
+  box-shadow: var(--shadow-lg);
+  font-size: var(--text-sm);
+  max-width: calc(100vw - var(--space-8));
+  animation: toast-slide-in var(--duration-normal) var(--ease-out);
+}
+
+@keyframes toast-slide-in {
+  from {
+    opacity: 0;
+    transform: translateX(-50%) translateY(20px);
+  }
+  to {
+    opacity: 1;
+    transform: translateX(-50%) translateY(0);
+  }
+}
+
+.toast-info {
+  border-color: var(--color-info);
+  background: linear-gradient(135deg, var(--color-background-elevated), rgba(34, 211, 238, 0.05));
+}
+
+.toast-success {
+  border-color: var(--color-success);
+  background: linear-gradient(135deg, var(--color-background-elevated), rgba(16, 185, 129, 0.05));
+}
+
+.toast-warning {
+  border-color: var(--color-warning);
+  background: linear-gradient(135deg, var(--color-background-elevated), rgba(245, 158, 11, 0.05));
+}
+
+.toast-error {
+  border-color: var(--color-error);
+  background: linear-gradient(135deg, var(--color-background-elevated), rgba(239, 68, 68, 0.05));
+}
+
+/* Mobile: position toast above control deck */
+@media (max-width: 640px) {
+  .toast {
+    bottom: calc(var(--control-deck-reserved-height, 140px) + var(--space-4) + env(safe-area-inset-bottom));
+  }
+}
+
+/* =============================================================================
+   3D VIEWER PLACEHOLDER - Engaging disabled state
+   ============================================================================= */
+
+.viewer-placeholder {
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+  justify-content: center;
+  min-height: 300px;
+  padding: var(--space-6);
+  text-align: center;
+  background:
+    radial-gradient(circle at 30% 30%, rgba(34, 211, 238, 0.08), transparent 50%),
+    radial-gradient(circle at 70% 70%, rgba(192, 132, 252, 0.08), transparent 50%),
+    var(--color-background-alt);
+  border: 1px solid var(--color-border-subtle);
+  border-radius: var(--radius-lg);
+}
+
+.viewer-placeholder__icon {
+  width: 80px;
+  height: 80px;
+  margin-bottom: var(--space-4);
+  opacity: 0.6;
+  color: var(--color-primary);
+}
+
+.viewer-placeholder__title {
+  font-size: var(--text-lg);
+  font-weight: var(--font-semibold);
+  color: var(--color-text);
+  margin-bottom: var(--space-2);
+}
+
+.viewer-placeholder__description {
+  font-size: var(--text-sm);
+  color: var(--color-text-muted);
+  max-width: 280px;
+  line-height: 1.5;
+  margin-bottom: var(--space-4);
+}
+
